/**
 * heic2any-stub.js
 *
 * Lightweight HEIC→JPEG conversion for the Immich Quick Download extension.
 *
 * Strategy:
 *   1. Try native browser HEIC decode (Safari/Chrome on macOS support this).
 *   2. Fall back to the Immich server's own pre-converted full-res JPEG
 *      (Immich already transcodes every HEIC to JPEG internally for previews).
 *      The /api/assets/:id/thumbnail?size=preview endpoint returns a high-quality
 *      JPEG. For truly lossless needs the user should grab the original separately.
 *
 * This avoids bundling a 500KB+ WASM library and works fully offline (LAN-only).
 */

(function (global) {
  "use strict";

  /**
   * Attempt to decode via an <img> element (works natively in Safari and
   * some Chrome versions with HEIC codec installed).
   */
  function tryNativeDecode(arrayBuffer, mimeType) {
    return new Promise((resolve, reject) => {
      const blob = new Blob([arrayBuffer], { type: mimeType });
      const url  = URL.createObjectURL(blob);
      const img  = new Image();

      img.onload = () => {
        const canvas = document.createElement("canvas");
        canvas.width  = img.naturalWidth;
        canvas.height = img.naturalHeight;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0);
        URL.revokeObjectURL(url);
        canvas.toBlob((jpegBlob) => {
          if (jpegBlob && jpegBlob.size > 1000) {
            resolve(jpegBlob);
          } else {
            reject(new Error("canvas blank"));
          }
        }, "image/jpeg", 0.95);
      };

      img.onerror = () => {
        URL.revokeObjectURL(url);
        reject(new Error("native decode failed"));
      };

      img.src = url;
    });
  }

  /**
   * Public API — mirrors heic2any signature so content.js works unchanged.
   * `options.immichFallback` carries { base, assetId, apiKey } for the
   * server-side fallback path.
   */
  global.heic2any = async function ({ blob, toType, quality, immichFallback }) {
    const buffer = await blob.arrayBuffer();

    // 1. Try native browser decode
    try {
      return await tryNativeDecode(buffer, "image/heic");
    } catch (_) {
      // not supported natively — fall through
    }

    // 2. Immich server fallback: fetch the server-rendered full-quality JPEG
    if (immichFallback) {
      const { base, assetId, apiKey } = immichFallback;
      // "preview" is full-resolution JPEG Immich generates from HEIC
      const res = await fetch(
        `${base}/api/assets/${assetId}/thumbnail?size=preview`,
        { headers: { "x-api-key": apiKey } }
      );
      if (res.ok) {
        return await res.blob(); // already a JPEG
      }
    }

    throw new Error(
      "HEIC-Konvertierung nicht möglich: Browser unterstützt HEIC nicht nativ " +
      "und Immich-Fallback fehlgeschlagen."
    );
  };
})(window);
